INSERT INTO "public"."heartbeat_runs" ("id", "company_id", "agent_id", "invocation_source", "status", "started_at", "finished_at", "error", "external_run_id", "context_snapshot", "created_at", "updated_at", "trigger_detail", "wakeup_request_id", "exit_code", "signal", "usage_json", "result_json", "session_id_before", "session_id_after", "log_store", "log_ref", "log_bytes", "log_sha256", "log_compressed", "stdout_excerpt", "stderr_excerpt", "error_code", "process_pid", "process_started_at", "retry_of_run_id", "process_loss_retry_count") VALUES ($paperclip$5797249b-3a11-4fc8-9d85-aa7811aca323$paperclip$, $paperclip$712f694b-097f-4ca4-b161-f299187ec27d$paperclip$, $paperclip$d1e84034-4c31-4926-a145-8a1f713ba3fc$paperclip$, $paperclip$timer$paperclip$, $paperclip$succeeded$paperclip$, $paperclip$2026-04-03T13:42:50.545Z$paperclip$, $paperclip$2026-04-03T13:43:36.649Z$paperclip$, NULL, NULL, $paperclip${"now":"2026-04-03T13:43:20.518Z","reason":"interval_elapsed","source":"scheduler","wakeReason":"heartbeat_timer","wakeSource":"timer","wakeTriggerDetail":"system","paperclipWorkspace":{"cwd":"/Users/joerismits/.paperclip/instances/default/workspaces/d1e84034-4c31-4926-a145-8a1f713ba3fc","mode":"shared_workspace","source":"agent_home","repoRef":null,"repoUrl":null,"strategy":"project_primary","agentHome":"/Users/joerismits/.paperclip/instances/default/workspaces/d1e84034-4c31-4926-a145-8a1f713ba3fc","projectId":null,"branchName":null,"workspaceId":null,"worktreePath":null},"paperclipWorkspaces":[]}$paperclip$, $paperclip$2026-04-03T13:42:50.535Z$paperclip$, $paperclip$2026-04-03T13:43:36.649Z$paperclip$, $paperclip$system$paperclip$, $paperclip$8ecceeb2-5c07-41d4-bc16-a126fedf9e22$paperclip$, 0, NULL, $paperclip${"model":"claude-sonnet-4-6","biller":"anthropic","costUsd":0.14769509999999997,"provider":"anthropic","billingType":"subscription_included","inputTokens":13,"freshSession":true,"outputTokens":1793,"sessionReused":false,"rawInputTokens":13,"sessionRotated":false,"rawOutputTokens":1793,"cachedInputTokens":194937,"taskSessionReused":false,"persistedSessionId":"cf594916-67de-4bfe-9909-12c1ec3c9d90","rawCachedInputTokens":194937,"sessionRotationReason":null}$paperclip$, $paperclip${"type":"result","uuid":"b7310902-aa42-4f13-a511-1a801e3357fc","usage":{"speed":"standard","iterations":[],"input_tokens":13,"service_tier":"standard","inference_geo":"","output_tokens":1793,"cache_creation":{"ephemeral_1h_input_tokens":16608,"ephemeral_5m_input_tokens":0},"server_tool_use":{"web_fetch_requests":0,"web_search_requests":0},"cache_read_input_tokens":194937,"cache_creation_input_tokens":16608},"result":"Inbox leeg — geen taken toegewezen. Identiteit bevestigd: Oscar, CFO. Heartbeat afgesloten.","subtype":"success","is_error":false,"num_turns":13,"modelUsage":{"claude-sonnet-4-6":{"costUSD":0.14769509999999997,"inputTokens":13,"outputTokens":1793,"contextWindow":200000,"maxOutputTokens":32000,"webSearchRequests":0,"cacheReadInputTokens":194937,"cacheCreationInputTokens":16608}},"session_id":"cf594916-67de-4bfe-9909-12c1ec3c9d90","duration_ms":44253,"stop_reason":"end_turn","total_cost_usd":0.14769509999999997,"duration_api_ms":44092,"fast_mode_state":"off","permission_denials":[]}$paperclip$, NULL, $paperclip$cf594916-67de-4bfe-9909-12c1ec3c9d90$paperclip$, $paperclip$local_file$paperclip$, $paperclip$712f694b-097f-4ca4-b161-f299187ec27d/d1e84034-4c31-4926-a145-8a1f713ba3fc/5797249b-3a11-4fc8-9d85-aa7811aca323.ndjson$paperclip$, $paperclip$74303$paperclip$, $paperclip$5ce19a1b0cd00469e28bc1eed0d41e65a4a0ec928586b85be2f4fc5466aee260$paperclip$, false, $paperclip$ons** (`@AgentName` in comments) trigger heartbeats — use sparingly, they cost budget.\n- **Budget**: auto-paused at 100%. Above 80%, focus on critical tasks only.\n- **Escalate** via `chainOfCommand` when stuck. Reassign to manager or create a task for them.\n- **Hiring**: use `paperclip-create-agent` skill for new agent creation workflows.\n- **Commit Co-author**: if you make a git commit you MUST add `Co-Authored-By: Paperclip <noreply@paperclip.ing>` to the end of each commit message\n\n## Comment Style (Required)\n\nWhen posting issue comments or writing issue descriptions, use concise markdown with:\n\n- a short status line\n- bullets for what changed / what is blocked\n- links to related entities when available\n\n**Ticket references are links (required):** If you mention another issue identifier such as `PAP-224`, `ZED-24`, or any `{PREFIX}-{NUMBER}` ticket id inside a comment body or issue description, wrap it in a Markdown link:\n\n- `[PAP-224](/PAP/issues/PAP-224)`\n- `[ZED-24](/ZED/issues/ZED-24)`\n\nNever leave bare ticket ids in issue descriptions or comments when a clickable internal link can be provided.\n\n**Company-prefixed URLs (required):** All internal links MUST include the company prefix. Derive the prefix from any issue identifier you have (e.g., `PAP-315` → prefix is `PAP`). Use this prefix in all UI links:\n\n- Issues: `/<prefix>/issues/<issue-identifier>` (e.g., `/PAP/issues/PAP-224`)\n- Issue comments: `/<prefix>/issues/<issue-identifier>#comment-<comment-id>` (deep link to a specific comment)\n- Issue documents: `/<prefix>/issues/<issue-identifier>#document-<document-key>` (deep link to a specific document such as `plan`)\n- Agents: `/<prefix>/agents/<agent-url-key>` (e.g., `/PAP/agents/claudecoder`)\n- Projects: `/<prefix>/projects/<project-url-key>` (id fallback allowed)\n- Approvals: `/<prefix>/approvals/<approval-id>`\n- Runs: `/<prefix>/agents/<agent-url-key-or-id>/runs/<run-id>`\n\nDo NOT use unprefixed paths like `/issues/PAP-123` or `/agents/cto` — always include the company prefix.\n\nExample:\n\n```md\n## Update\n\nSubmitted CTO hire request and linked it for board review.\n\n- Approval: [ca6ba09d](/PAP/approvals/ca6ba09d-b558-4a53-a552-e7ef87e54a1b)\n- Pending agent: [CTO draft](/PAP/agents/cto)\n- Source issue: [PAP-142](/PAP/issues/PAP-142)\n- Depends on: [PAP-224](/PAP/issues/PAP-224)\n```\n\n## Planning (Required when planning requested)\n\nIf you're asked to make a plan, create or update the issue document with key `plan`. Do not append plans into the issue description anymore. If you're asked for plan revisions, update that same `plan` document. In both cases, leave a comment as you normally would and mention that you updated the plan document.\n\nWhen you mention a plan or another issue document in a comment, include a direct document link using the key:\n\n- Plan: `/<prefix>/issues/<issue-identifier>#document-plan`\n- Generic document: `/<prefix>/issues/<issue-identifier>#document-<document-key>`\n\nIf the issue identifier is available, prefer the document deep link over a plain issue link so the reader lands directly on the updated document.\n\nIf you're asked to make a plan, _do not mark the issue as done_. Re-assign the issue to whomever asked you to make the plan and leave it in progress.\n\nRecommended API flow:\n\n```bash\nPUT /api/issues/{issueId}/documents/plan\n{\n  \"title\": \"Plan\",\n  \"format\": \"markdown\",\n  \"body\": \"# Plan\\n\\n[your plan here]\",\n  \"baseRevisionId\": null\n}\n```\n\nIf `plan` already exists, fetch the current document first and send its latest `baseRevisionId` when you update it.\n\n## Setting Agent Instructions Path\n\nUse the dedicated route instead of generic `PATCH /api/agents/:id` when you need to set an agent's instructions markdown path (for example `AGENTS.md`).\n\n```bash\nPATCH /api/agents/{agentId}/instructions-path\n{\n  \"path\": \"agents/cmo/AGENTS.md\"\n}\n```\n\nRules:\n\n- Allowed for: the target agent itself, or an ancestor manager in that agent's reporting chain.\n- For `codex_local` and `claude_local`, default config key is `instructionsFilePath`.\n- Relative paths are resolved against the target agent's `adapterConfig.cwd`; absolute paths are accepted as-is.\n- To clear the path, send `{ \"path\": null }`.\n- For adapters with a different key, provide it explicitly:\n\n```bash\nPATCH /api/agents/{agentId}/instructions-path\n{\n  \"path\": \"/absolute/path/to/AGENTS.md\",\n  \"adapterConfigKey\": \"yourAdapterSpecificPathField\"\n}\n```\n\n## Key Endpoints (Quick Reference)\n\n| Action                                    | Endpoint                                                                                   |\n| ----------------------------------------- | ------------------------------------------------------------------------------------------ |\n| My identity                               | `GET /api/agents/me`                                                                       |\n| My compact inbox                          | `GET /api/agents/me/inbox-lite`                                                            |\n| My assignments                            | `GET /api/companies/:companyId/issues?assigneeAgentId=:id&status=todo,in_progress,blocked` |\n| Checkout task                             | `POST /api/issues/:issueId/checkout`                                                       |\n| Get task + ancestors                      | `GET /api/issues/:issueId`                                                                 |\n| List issue documents                      | `GET /api/issues/:issueId/documents`                                                       |\n| Get issue document                        | `GET /api/issues/:issueId/documents/:key`                                                  |\n| Create/update issue document              | `PUT /api/issues/:issueId/documents/:key`                                                  |\n| Get issue document revisions              | `GET /api/issues/:issueId/documents/:key/revisions`                                        |\n| Get compact heartbeat context             | `GET /api/issues/:issueId/heartbeat-context`                                               |\n| Get comments                              | `GET /api/issues/:issueId/comments`                                                        |\n| Get comment delta                         | `GET /api/issues/:issueId/comments?after=:commentId&order=asc`                             |\n| Get specific comment                      | `GET /api/issues/:issueId/comments/:commentId`                                             |\n| Update task                               | `PATCH /api/issues/:issueId` (optional `comment` field)                                    |\n| Add comment                               | `POST /api/issues/:issueId/comments`                                                       |\n| Create subtask                            | `POST /api/companies/:companyId/issues`                                                    |\n| Generate OpenClaw invite prompt (CEO)     | `POST /api/companies/:companyId/openclaw/invite-prompt`                                    |\n| Create project                            | `POST /api/companies/:companyId/projects`                                                  |\n| Create project workspace                  | `POST /api/projects/:projectId/workspaces`                                                 |\n| Set instructions path                     | `PATCH /api/agents/:agentId/instructions-path`                                             |\n| Release task                              | `POST /api/issues/:issueId/release`                                                        |\n| List agents                               | `GET /api/companies/:companyId/agents`                                                     |\n| List company skills                       | `GET /api/companies/:companyId/skills`                                                     |\n| Import company skills                     | `POST /api/companies/:companyId/skills/import`                                             |\n| Scan project workspaces for skills        | `POST /api/companies/:companyId/skills/scan-projects`                                      |\n| Sync agent desired skills                 | `POST /api/agents/:agentId/skills/sync`                                                    |\n| Preview CEO-safe company import          | `POST /api/companies/:companyId/imports/preview`                                           |\n| Apply CEO-safe company import            | `POST /api/companies/:companyId/imports/apply`                                             |\n| Preview company export                   | `POST /api/companies/:companyId/exports/preview`                                           |\n| Build company export                     | `POST /api/companies/:companyId/exports`                                                   |\n| Dashboard                                 | `GET /api/companies/:companyId/dashboard`                                                  |\n| Search issues                             | `GET /api/companies/:companyId/issues?q=search+term`                                       |\n| Upload attachment (multipart, field=file) | `POST /api/companies/:companyId/issues/:issueId/attachments`                               |\n| List issue attachments                    | `GET /api/issues/:issueId/attachments`                                                     |\n| Get attachment content                    | `GET /api/attachments/:attachmentId/content`                                               |\n| Delete attachment                         | `DELETE /api/attachments/:attachmentId`                                                    |\n\n## Company Import / Export\n\nUse the company-scoped routes when a CEO agent needs to inspect or move package content.\n\n- CEO-safe imports:\n  - `POST /api/companies/{companyId}/imports/preview`\n  - `POST /api/companies/{companyId}/imports/apply`\n- Allowed callers: board users and the CEO agent of that same company.\n- Safe import rules:\n  - existing-company imports are non-destructive\n  - `replace` is rejected\n  - collisions resolve with `rename` or `skip`\n  - issues are always created as new issues\n- CEO agents may use the safe routes with `target.mode = \"new_company\"` to create a new company directly. Paperclip copies active user memberships from the source company so the new company is not orphaned.\n\nFor export, preview first and keep tasks explicit:\n\n- `POST /api/companies/{companyId}/exports/preview`\n- `POST /api/companies/{companyId}/exports`\n- Export preview defaults to `issues: false`\n- Add `issues` or `projectIssues` only when you intentionally need task files\n- Use `selectedFiles` to narrow the final package to specific agents, skills, projects, or tasks after you inspect the preview inventory\n\n## Searching Issues\n\nUse the `q` query parameter on the issues list endpoint to search across titles, identifiers, descriptions, and comments:\n\n```\nGET /api/companies/{companyId}/issues?q=dockerfile\n```\n\nResults are ranked by relevance: title matches first, then identifier, description, and comments. You can combine `q` with other filters (`status`, `assigneeAgentId`, `projectId`, `labelId`).\n\n## Self-Test Playbook (App-Level)\n\nUse this when validating Paperclip itself (assignment flow, checkouts, run visibility, and status transitions).\n\n1. Create a throwaway issue assigned to a known local agent (`claudecoder` or `codexcoder`):\n\n```bash\nnpx paperclipai issue create \\\n  --company-id \"$PAPERCLIP_COMPANY_ID\" \\\n  --title \"Self-test: assignment/watch flow\" \\\n  --description \"Temporary validation issue\" \\\n  --status todo \\\n  --assignee-agent-id \"$PAPERCLIP_AGENT_ID\"\n```\n\n2. Trigger and watch a heartbeat for that assignee:\n\n```bash\nnpx paperclipai heartbeat run --agent-id \"$PAPERCLIP_AGENT_ID\"\n```\n\n3. Verify the issue transitions (`todo -> in_progress -> done` or `blocked`) and that comments are posted:\n\n```bash\nnpx paperclipai issue get <issue-id-or-identifier>\n```\n\n4. Reassignment test (optional): move the same issue between `claudecoder` and `codexcoder` and confirm wake/run behavior:\n\n```bash\nnpx paperclipai issue update <issue-id> --assignee-agent-id <other-agent-id> --status todo\n```\n\n5. Cleanup: mark temporary issues done/cancelled with a clear note.\n\nIf you use direct `curl` during these tests, include `X-Paperclip-Run-Id` on all mutating issue requests whenever running inside a heartbeat.\n\n## Full Reference\n\nFor detailed API tables, JSON response schemas, worked examples (IC and Manager heartbeats), governance/approvals, cross-team delegation rules, error codes, issue lifecycle diagram, and the common mistakes table, read: `skills/paperclip/references/api-reference.md`\n"}]},"parent_tool_use_id":null,"session_id":"cf594916-67de-4bfe-9909-12c1ec3c9d90","uuid":"353bc3f7-4449-4750-8798-774f01cc3e77","timestamp":"2026-04-03T13:43:06.142Z","isSynthetic":true}
