 -L \"$dst_item\" ]] && rm \"$dst_item\"\n      sync_dir \"$item\" \"$dst_item\"\n    else\n      if [[ -L \"$dst_item\" ]]; then\n        local existing=$(readlink \"$dst_item\")\n        [[ \"$existing\" = \"$item\" ]] && continue\n        rm \"$dst_item\"\n      elif [[ -e \"$dst_item\" ]]; then\n        continue\n      fi\n      ln -s \"$item\" \"$dst_item\"\n    fi\n  done\n}\n\nfor i in {1..${#AGENT_NAMES[@]}}; do\n  name=\"${AGENT_NAMES[$i]}\"\n  ws=\"$WORKSPACES/${AGENT_IDS[$i]}\"\n  [[ -d \"$ws\" ]] || continue\n  sync_dir \"$ws\" \"$VAULT/$name\"\ndone\n\necho \"Vault synced at $(date)\"\n"}}
